                                                      });
                                                        }

                                                          void _onToggleVideo() {
                                                              setState(() {
                                                                    _isVideoOff = !_isVideoOff;
                                                                        });
                                                                          }

                                                                            void _onSwitchCamera() {}

                                                                              @override
                                                                                void dispose() {
                                                                                    super.dispose();
                                                                                      }

